module lookup_table(
    input [3:0] data_in,
    output reg [2:0] data_out
);

reg [2:0] lut_memory [15:0];

initial begin
    lut_memory[0] = 3'b011;
    lut_memory[1] = 3'b000;
    lut_memory[2] = 3'b101;
    lut_memory[3] = 3'b010;
    lut_memory[4] = 3'b111;
    lut_memory[5] = 3'b001;
    lut_memory[6] = 3'b100;
    lut_memory[7] = 3'b110;
    lut_memory[8] = 3'b010;
    lut_memory[9] = 3'b100;
    lut_memory[10] = 3'b001;
    lut_memory[11] = 3'b111;
    lut_memory[12] = 3'b110;
    lut_memory[13] = 3'b011;
    lut_memory[14] = 3'b000;
    lut_memory[15] = 3'b101;
end

always @(*) begin
    data_out = lut_memory[data_in];
end

endmodule
